var dataList = new List<string>();
Serial.Open();
string? line;
while ((line = Serial.ReadLine()) != null) dataList.Add(line);

int ok = 0, bad = 0;
foreach (var d in dataList)
{
    if (string.IsNullOrEmpty(d)) bad++;
    else ok++;
}
Print($"正常: {ok} 条, 异常: {bad} 条");
